import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import BiometricPrompt from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    checkBiometry();
  }, []);

  const checkBiometry = async () => {
    try {
      const canUseBiometrics = await BiometricPrompt.isSupported();
      if (canUseBiometrics) {
        const biometryType = await BiometricPrompt.getEnrolledBiometrics();
        if (biometryType === 'FaceID' || biometryType === 'Touch ID') {
          authenticateWithBiometrics();
        } else {
          Alert.alert('No Face ID or Touch ID available');
        }
      } else {
        Alert.alert('Device does not support biometric authentication');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const authenticateWithBiometrics = async () => {
    try {
      const result = await BiometricPrompt.authenticate({
        promptMessage: 'Please verify your identity',
        cancelLabel: 'Cancel',
        fallbackLabel: 'Use password instead',
      });
      if (result) {
        setIsAuthenticated(true);
        storeAuthStatus();
      }
    } catch (error) {
      console.error(error);
    }
  };

  const storeAuthStatus = async () => {
    try {
      await AsyncStorage.setItem('isAuthenticated', 'true');
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    checkLoginScreen();
  }, [isAuthenticated]);

  const checkLoginScreen = async () => {
    try {
      const isAuthed = await AsyncStorage.getItem('isAuthenticated');
      if (isAuthed === 'true') {
        setIsAuthenticated(true);
      } else {
        // Show login screen
      }
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      {isAuthenticated ? (
        <Text>Authenticated</Text>
      ) : (
        <Button title="Authenticate" onPress={authenticateWithBiometrics} />
      )}
    </View>
  );
};

export default App;